<?php
 namespace League\CommonMark; use League\CommonMark\Util\Xml; class HtmlElement { protected $tagName; protected $attributes = []; protected $contents; protected $selfClosing = false; public function __construct(string $tagName, array $attributes = [], $contents = '', bool $selfClosing = false) { $this->tagName = $tagName; $this->attributes = $attributes; $this->selfClosing = $selfClosing; $this->setContents($contents ?? ''); } public function getTagName(): string { return $this->tagName; } public function getAllAttributes(): array { return $this->attributes; } public function getAttribute(string $key): ?string { if (!isset($this->attributes[$key])) { return null; } return $this->attributes[$key]; } public function setAttribute(string $key, string $value): self { $this->attributes[$key] = $value; return $this; } public function getContents(bool $asString = true) { if (!$asString) { return $this->contents; } return $this->getContentsAsString(); } public function setContents($contents): self { $this->contents = $contents ?? ''; return $this; } public function __toString(): string { $result = '<' . $this->tagName; foreach ($this->attributes as $key => $value) { $result .= ' ' . $key . '="' . Xml::escape($value) . '"'; } if ($this->contents !== '') { $result .= '>' . $this->getContentsAsString() . '</' . $this->tagName . '>'; } elseif ($this->selfClosing && $this->tagName === 'input') { $result .= '>'; } elseif ($this->selfClosing) { $result .= ' />'; } else { $result .= '></' . $this->tagName . '>'; } return $result; } private function getContentsAsString(): string { if (\is_string($this->contents)) { return $this->contents; } if (\is_array($this->contents)) { return \implode('', $this->contents); } return (string) $this->contents; } } 